import{_ as e,o as t,c as s,ag as i}from"./chunks/framework.DEs8X8sU.js";const k=JSON.parse('{"title":"スタッフ画面 PWA 化","description":"","frontmatter":{"feature_id":"pwa-staff","title":"スタッフ画面 PWA 化","chapter":9,"plan":["base"],"role":["posla_admin","owner","manager"],"audience":"internal","keywords":["PWA","ServiceWorker","manifest","ホーム画面","オフライン","スタッフ"],"related":["/internal/05-operations.md","/internal/06-troubleshoot.md"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"posla"},"headers":[],"relativePath":"internal/09-pwa.md","filePath":"internal/09-pwa.md"}'),d={name:"internal/09-pwa.md"};function l(o,a,n,c,r,p){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="_9-スタッフ画面-pwa-化-meal-posla-jp" tabindex="-1">9. スタッフ画面 PWA 化 (meal.posla.jp) <a class="header-anchor" href="#_9-スタッフ画面-pwa-化-meal-posla-jp" aria-label="Permalink to &quot;9. スタッフ画面 PWA 化 (meal.posla.jp)&quot;">​</a></h1><h2 id="_9-0-はじめにお読みください" tabindex="-1">9.0 はじめにお読みください <a class="header-anchor" href="#_9-0-はじめにお読みください" aria-label="Permalink to &quot;9.0 はじめにお読みください&quot;">​</a></h2><p>POSLA の <strong>スタッフ向け業務画面のみ</strong> を PWA (Progressive Web App) として構成し、タブレットやスマホのホーム画面に追加 → 1 タップでアプリのように起動できるようにする。<strong>顧客側のセルフメニュー / 予約 / テイクアウト画面は意図的に PWA から除外</strong> している。</p><div class="warning custom-block"><p class="custom-block-title">顧客セルフメニューはブラウザ運用</p><p>顧客が QR からアクセスするセルフメニュー (<code>public/customer/menu.html</code> 等) には Service Worker / manifest を一切載せない。 理由:</p><ul><li>1 回限りのスキャン → 注文 → 会計でセッションが終わる短期利用フロー</li><li>ホーム画面追加されると古いキャッシュが残るリスク (来店ごとにメニュー差分があるため)</li><li>セッション情報・QR トークン・テーブル ID が URL に含まれるため、過去のキャッシュが他人に流用されるリスク</li><li>二重防御: SW の fetch handler でも <code>/public/customer/</code> および <code>/api/customer/</code> を含む request は強制 passthrough</li></ul></div><h2 id="_9-1-対象画面とスコープ" tabindex="-1">9.1 対象画面とスコープ <a class="header-anchor" href="#_9-1-対象画面とスコープ" aria-label="Permalink to &quot;9.1 対象画面とスコープ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>スコープ</th><th>パス</th><th>用途</th><th>manifest theme</th><th>アイコン</th></tr></thead><tbody><tr><td><code>/public/admin/</code></td><td><code>index.html</code> <code>dashboard.html</code> <code>owner-dashboard.html</code> <code>device-setup.html</code></td><td>管理者・店長操作</td><td><code>#1976d2</code> (青)</td><td>管</td></tr><tr><td><code>/public/kds/</code></td><td><code>index.html</code> <code>cashier.html</code> <code>sold-out.html</code></td><td>キッチン・レジ</td><td><code>#2e7d32</code> (緑)</td><td>厨</td></tr><tr><td><code>/public/handy/</code></td><td><code>index.html</code> <code>pos-register.html</code></td><td>ハンディ POS</td><td><code>#ff6f00</code> (橙)</td><td>配</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">accounting.html を除外する理由</p><p><code>public/kds/accounting.html</code> は 2026-04-02 以降 <code>cashier.html</code> への redirect 専用。空ボディなので PWA 化しない。</p></div><h2 id="_9-2-ファイル構成" tabindex="-1">9.2 ファイル構成 <a class="header-anchor" href="#_9-2-ファイル構成" aria-label="Permalink to &quot;9.2 ファイル構成&quot;">​</a></h2><p>各スコープに 3 ファイル + アイコン 4 種を配置:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public/admin/</span></span>
<span class="line"><span>├── manifest.webmanifest      ← Web App Manifest</span></span>
<span class="line"><span>├── sw.js                     ← Service Worker (scope: /public/admin/)</span></span>
<span class="line"><span>├── pwa-register.js           ← クライアント登録スクリプト</span></span>
<span class="line"><span>└── icons/</span></span>
<span class="line"><span>    ├── icon.svg              ← マスターベクター</span></span>
<span class="line"><span>    ├── icon-192.png          ← Android 推奨</span></span>
<span class="line"><span>    ├── icon-512.png          ← splash 用</span></span>
<span class="line"><span>    └── apple-touch-icon.png  ← iOS Safari 用 (180x180)</span></span></code></pre></div><p><code>public/kds/</code> <code>public/handy/</code> も同構成。</p><h2 id="_9-3-キャッシュ戦略" tabindex="-1">9.3 キャッシュ戦略 <a class="header-anchor" href="#_9-3-キャッシュ戦略" aria-label="Permalink to &quot;9.3 キャッシュ戦略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>対象</th><th>戦略</th><th>理由</th></tr></thead><tbody><tr><td><code>/api/*</code></td><td><strong>キャッシュしない (passthrough)</strong></td><td>業務データ整合性。注文・会計は常に最新</td></tr><tr><td><code>/api/customer/*</code></td><td>passthrough (二重防御)</td><td>同上</td></tr><tr><td><code>/public/customer/*</code></td><td>passthrough (二重防御)</td><td>顧客側 PWA 化禁止</td></tr><tr><td>POST / PATCH / DELETE / PUT</td><td>passthrough</td><td>mutating request はキャッシュしない</td></tr><tr><td>URL に <code>token</code> <code>session</code> <code>checkout</code> <code>reservation</code> <code>store_id</code> <code>table_id</code> <code>pin</code> <code>staff_pin</code> 含む</td><td>passthrough</td><td>個別セッション・取引 ID は他人に流用される</td></tr><tr><td>HTML</td><td>network-first → 失敗時キャッシュ</td><td>オフライン時もログイン画面等を表示</td></tr><tr><td>CSS / JS / 画像 / フォント / manifest</td><td>stale-while-revalidate</td><td>更新は次回読込で取得</td></tr></tbody></table><h2 id="_9-4-業務データ整合性のための非対応" tabindex="-1">9.4 業務データ整合性のための非対応 <a class="header-anchor" href="#_9-4-業務データ整合性のための非対応" aria-label="Permalink to &quot;9.4 業務データ整合性のための非対応&quot;">​</a></h2><p>以下は意図的に <strong>実装しない</strong>:</p><ul><li>オフライン注文の自動キュー (会計差分の温床)</li><li>オフライン会計の自動再送 (二重課金リスク)</li><li>バックグラウンド同期 (Background Sync API)</li><li>プッシュ通知 (Web Push)</li><li>IndexedDB によるメニュー / 注文ローカルストア</li></ul><p>オフライン時は HTML のキャッシュ表示のみで、業務操作は不可 (network-first で 503 表示)。</p><h2 id="_9-5-バージョニングと更新" tabindex="-1">9.5 バージョニングと更新 <a class="header-anchor" href="#_9-5-バージョニングと更新" aria-label="Permalink to &quot;9.5 バージョニングと更新&quot;">​</a></h2><p>各 SW の cache name にバージョン:</p><ul><li><code>posla-admin-static-v1</code></li><li><code>posla-kds-static-v1</code></li><li><code>posla-handy-static-v1</code></li></ul><p>新版デプロイ時は <code>sw.js</code> の <code>VERSION = &#39;v1&#39;</code> を <code>&#39;v2&#39;</code> などに上げる。<code>activate</code> ハンドラで <code>posla-XXX-</code> prefix の旧 cache を全削除 → 古いアセット混在事故を防止。</p><p><code>skipWaiting()</code> + <code>clients.claim()</code> を使用しているため、新版 SW は <strong>既存タブを含めて即座に切替わる</strong> (再読込不要)。</p><div class="tip custom-block"><p class="custom-block-title">skipWaiting の判断理由</p><ul><li>install 直後に <code>skipWaiting()</code> → waiting フェーズをスキップ</li><li>activate 時に <code>clients.claim()</code> → 既存タブも即座に新 SW の制御下に置く</li><li>結果として、<strong>新版デプロイ後、既存タブの次のリクエストから新 SW が応答</strong>する</li><li>API は常に passthrough なので、業務操作中に SW が切り替わってもレスポンス形式不整合は発生しない (REST 呼び出しは SW を通らない)</li><li>静的アセット (CSS/JS) は順次差し替わる。古いキャッシュは activate 時の <code>caches.delete()</code> で除去</li><li>業務中の突発切替リスク &lt; 古い JS が決済 API レスポンス形式と合わない事故、と判断</li></ul></div><h2 id="_9-6-ホーム画面への追加方法" tabindex="-1">9.6 ホーム画面への追加方法 <a class="header-anchor" href="#_9-6-ホーム画面への追加方法" aria-label="Permalink to &quot;9.6 ホーム画面への追加方法&quot;">​</a></h2><h3 id="iphone-safari" tabindex="-1">iPhone Safari <a class="header-anchor" href="#iphone-safari" aria-label="Permalink to &quot;iPhone Safari&quot;">​</a></h3><ol><li>Safari で対象 URL を開く (例: <code>https://meal.posla.jp/public/admin/dashboard.html</code>)</li><li>共有ボタン → 「ホーム画面に追加」</li><li>名前 (例: <code>POSLA管理</code>) を確認 → 追加</li><li>ホーム画面のアイコンタップで standalone 起動</li></ol><h3 id="android-chrome" tabindex="-1">Android Chrome <a class="header-anchor" href="#android-chrome" aria-label="Permalink to &quot;Android Chrome&quot;">​</a></h3><ol><li>Chrome で対象 URL を開く</li><li>メニュー (︙) → 「ホーム画面に追加」または「アプリをインストール」 (PWA インストールバナーが出る場合あり)</li><li>ホーム画面アイコンから起動</li></ol><h2 id="_9-7-トラブルシューティング" tabindex="-1">9.7 トラブルシューティング <a class="header-anchor" href="#_9-7-トラブルシューティング" aria-label="Permalink to &quot;9.7 トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>ホーム画面追加メニューが出ない</td><td>manifest 読み込み失敗 / icon サイズ不足</td><td>DevTools → Application → Manifest を確認</td></tr><tr><td>古い JS / CSS が表示される</td><td>SW キャッシュが残存</td><td>DevTools → Application → Service Workers → Unregister + Storage Clear、または Ctrl+Shift+R</td></tr><tr><td>API レスポンスが古い</td><td>通常はキャッシュしない設定。されていたら設定異常</td><td>DevTools → Network で <code>(from ServiceWorker)</code> 表示がないか確認</td></tr><tr><td>オフライン時の表示が崩れる</td><td>HTML はキャッシュされるが API は 503 になるので部分崩壊</td><td>期待通り。業務継続不可なのは仕様</td></tr><tr><td>顧客 menu.html が PWA 化されている</td><td>二重バグ</td><td>本仕様に違反。<code>public/customer/</code> 配下に SW 登録があれば即削除</td></tr></tbody></table><h2 id="_9-8-確認コマンド" tabindex="-1">9.8 確認コマンド <a class="header-anchor" href="#_9-8-確認コマンド" aria-label="Permalink to &quot;9.8 確認コマンド&quot;">​</a></h2><h3 id="顧客側に-pwa-登録が混入していないこと" tabindex="-1">顧客側に PWA 登録が混入していないこと <a class="header-anchor" href="#顧客側に-pwa-登録が混入していないこと" aria-label="Permalink to &quot;顧客側に PWA 登録が混入していないこと&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;serviceWorker|manifest.webmanifest|pwa-register|navigator.serviceWorker&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/customer</span></span></code></pre></div><p>→ ヒットゼロが期待値。</p><h3 id="service-worker-が-api-をキャッシュしないことの確認" tabindex="-1">Service Worker が <code>/api/</code> をキャッシュしないことの確認 <a class="header-anchor" href="#service-worker-が-api-をキャッシュしないことの確認" aria-label="Permalink to &quot;Service Worker が \`/api/\` をキャッシュしないことの確認&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/api/|caches\\.put|caches\\.open|fetch\\(&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/admin/sw.js</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/kds/sw.js</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/handy/sw.js</span></span></code></pre></div><p>→ <code>/api/</code> 検出は passthrough 分岐のみのはず。</p><h3 id="各スコープ-scope-の確認" tabindex="-1">各スコープ scope の確認 <a class="header-anchor" href="#各スコープ-scope-の確認" aria-label="Permalink to &quot;各スコープ scope の確認&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;manifest.webmanifest&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meal.posla.jp/public/admin/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.html</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/kds/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.html</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  meal.posla.jp/public/handy/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.html</span></span></code></pre></div><p>→ 全 staff HTML がリストに含まれること。</p><h2 id="_9-9-デプロイ対象ファイル" tabindex="-1">9.9 デプロイ対象ファイル <a class="header-anchor" href="#_9-9-デプロイ対象ファイル" aria-label="Permalink to &quot;9.9 デプロイ対象ファイル&quot;">​</a></h2><ul><li><code>public/admin/manifest.webmanifest</code> <code>sw.js</code> <code>pwa-register.js</code> <code>icons/*</code></li><li><code>public/kds/manifest.webmanifest</code> <code>sw.js</code> <code>pwa-register.js</code> <code>icons/*</code></li><li><code>public/handy/manifest.webmanifest</code> <code>sw.js</code> <code>pwa-register.js</code> <code>icons/*</code></li><li>編集された 9 HTML (<code>&lt;head&gt;</code> 末尾と <code>&lt;body&gt;</code> 末尾に各 1〜3 行追加)</li></ul><h2 id="_9-x-更新履歴" tabindex="-1">9.X 更新履歴 <a class="header-anchor" href="#_9-x-更新履歴" aria-label="Permalink to &quot;9.X 更新履歴&quot;">​</a></h2><ul><li><strong>2026-04-19</strong>: 初版 (Q1=A スコープ別カラー / Q2=B 全 staff HTML 対象)</li></ul>`,44)])])}const u=e(d,[["render",l]]);export{k as __pageData,u as default};
